module RefModule (  
    input clk,  
    input reset,  
    input enable,  
    output reg [2:0] active_channel  
);  

    reg [2:0] channel;  

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt) begin  
        if (reset) begin  
            channel <= 3'b000;  
            active_channel <= 3'b000;  
        end else if (enable) begin  
            if (channel < 3'b111)  
                channel <= channel + 1;  
            else  
                channel <= 3'b000;  
            active_channel <= channel;  
        end  
    end  
endmodule
